  ('Hip 90/90 Stretch Sequence', 'hip-90-90-stretch-sequence', 'cool_down', NULL, 'Mobility', 'Restore hip internal and external rotation for sharp route breaks and hip flips.', 'v_ZnFMgCiAg', NULL, '{None}'::text[], '{wr_db}'::text[], '{fc673039-ec26-4c0e-8c32-14d6dafc36d3,9f89a874-b3d4-4615-8c35-53d26c02fa15}'::text[], '{Duration,ROM}'::text[], 'Transition smoothly between 90/90 positions.', 'Hips should open without pinching.', 'Do not force end range or twist through the low back.', 4, NULL, NULL, 'low', 1, NULL, NULL, true, false),
