  ('Thoracic Rotation Drills', 'thoracic-rotation-drills', 'cool_down', NULL, 'Mobility', 'Improve thoracic rotation to support efficient throwing mechanics.', 'FGIGlBUFbKc', NULL, '{None}'::text[], '{quarterback}'::text[], '{e43ab0e8-ec2a-451b-814d-266b3ca247b0}'::text[], '{Duration,Rotations}'::text[], 'Rotate through the upper back while keeping hips stable.', 'More torso rotation without shoulder strain.', 'Do not over-rotate through the lower back.', 4, NULL, NULL, 'low', 1, NULL, NULL, true, false),
  ('Box Breathing', 'box-breathing', 'recovery', NULL, NULL, NULL, 'paqAzWbLIUw', NULL, NULL, NULL, NULL, NULL, 'Inhale for 4 seconds, hold for 4, exhale for 4, hold for 4. Repeat for 5 rounds. Sit or lie comfortably with eyes closed.', 'Heart rate should slow noticeably within 3 rounds. The exhale phase is the most calming — make it deliberate.', NULL, 0, NULL, NULL, 'beginner', 1, 5, NULL, true, false),
  ('Hip Flexor Lunge Stretch', 'hip-flexor-lunge-stretch', 'recovery', NULL, NULL, NULL, 'v_ZnFMgCiAg', NULL, NULL, NULL, NULL, NULL, 'Kneel on one knee in a lunge position. Squeeze the glute of the rear leg and shift your hips forward until you feel a stretch at the front of the rear hip. Hold and switch.', 'You should feel an elongation at the front of the hip and thigh — not in the knee. Posterior pelvic tilt deepens it.', NULL, 0, NULL, NULL, 'beginner', 1, NULL, 45, true, false),
  ('Pigeon Pose', 'pigeon-pose', 'recovery', NULL, NULL, NULL, 'qZ_KgFnRlhI', NULL, NULL, NULL, NULL, NULL, 'From a push-up position, bring one knee forward toward the same-side wrist. Lower your hips and fold forward over the shin. Hold, breathe, and switch sides.', 'Deep release through the outer hip and glute. Breathe through any tightness — do not push into sharp pain.', NULL, 0, NULL, NULL, 'beginner', 1, NULL, 60, true, false),
  ('Seated Hamstring Stretch', 'seated-hamstring-stretch', 'recovery', NULL, NULL, NULL, 'LB2V2jVHudc', NULL, NULL, NULL, NULL, NULL, 'Sit tall on the floor with legs extended. Hinge from the hips (not rounding the lower back) and reach toward the feet. Hold the position with soft knees.', 'Steady pull behind the knee and up through the hamstring. Breathing deeply should deepen the stretch.', NULL, 0, NULL, NULL, 'beginner', 1, NULL, 45, true, false),
  ('Supine Spinal Twist', 'supine-spinal-twist', 'recovery', NULL, NULL, NULL, 'FGIGlBUFbKc', NULL, NULL, NULL, NULL, NULL, 'Lie on your back. Draw one knee to the chest, then guide it across the body with the opposite hand. Extend both arms wide and breathe. Repeat other side.', 'Gentle wringing sensation through the thoracic and lumbar spine. The shoulder that lifts is normal — breathe it down.', NULL, 0, NULL, NULL, 'beginner', 1, NULL, 45, true, false),
  ('Copenhagen Plank', 'copenhagen-plank-warmup', 'warm_up', NULL, NULL, NULL, 'Pk6P-q1UYYI', NULL, NULL, NULL, NULL, NULL, 'Lie on your side. Rest top foot on a bench or box. Bottom leg hangs free. Press up so body forms a straight line. Hold with top-leg adductor doing the work.', 'Distinct pull in the inner thigh of the top leg — that is the adductor engaging. This is the primary groin injury prevention exercise for sprinters.', 'If groin cramps: shorten hold to 15s and build up. If hip drops: reduce leverage by placing knee (not ankle) on bench.', 3, NULL, NULL, NULL, 1, NULL, 30, true, false),
  ('Single Arm Plank', 'single-arm-plank-warmup', 'warm_up', NULL, NULL, NULL, 'Pk6P-q1UYYI', NULL, NULL, NULL, NULL, NULL, 'Start in forearm plank. Extend one arm forward, parallel to the floor. Fight the urge to rotate — keep both hips square to the ground.', 'Strong oblique pull on the working side fighting rotation. If you feel nothing in the obliques, you are rotating too much.', 'If hips rotate: reduce arm lift height. If lower back takes over: return to two-arm plank and build more time.', 2, NULL, NULL, NULL, 1, NULL, 30, true, false),
  ('Straight Plank', 'straight-plank-warmup', 'warm_up', NULL, NULL, NULL, 'Pk6P-q1UYYI', NULL, NULL, NULL, NULL, NULL, 'Forearms on ground, elbows under shoulders. Body forms a rigid line from heels to head. Brace hard — tuck the pelvis slightly so your lower back stays flat.', 'Deep tension through the entire core simultaneously — abs, obliques, glutes all on at once. Lower back feels stable, not compressed.', 'If hips sag: squeeze glutes harder and tuck pelvis. If lower back aches: reduce to 30s and rebuild hip flexor length.', 2, NULL, NULL, NULL, 1, NULL, 60, true, false)
) AS v(name, slug, category, subcategory, movement_pattern, description, video_id, video_url,
       equipment_needed, position_specific, applicable_positions, metrics_tracked,
       how_text, feel_text, compensation_text, load_contribution_au, muscle_groups,
       target_muscles, difficulty_level, default_sets, default_reps, default_hold_seconds,
       active, is_high_intensity)
WHERE NOT EXISTS (
  SELECT 1 FROM public.exercises e WHERE e.name = v.name AND e.category = v.category
);
